import{_ as a,o as s,c as e,ak as l}from"./chunks/framework.DwHlt8HN.js";const h=JSON.parse('{"title":"构建工具","description":"","frontmatter":{},"headers":[],"relativePath":"devops/build-tool/index.md","filePath":"devops/build-tool/index.md","lastUpdated":1774360456000}'),p={name:"devops/build-tool/index.md"};function r(t,n,i,d,o,c){return s(),e("div",null,[...n[0]||(n[0]=[l(`<h1 id="构建工具" tabindex="-1">构建工具 <a class="header-anchor" href="#构建工具" aria-label="Permalink to “构建工具”">​</a></h1><p>「每次改完代码，点点鼠标等编译——这大概是大多数人对构建工具的全部认知。」</p><p>但如果你只把 Maven 或 Gradle 当作「编译工具」，就太低估它们了。从依赖解析、增量构建、多环境打包到插件扩展，构建工具实际上是<strong>软件构建流水线的核心枢纽</strong>。它决定了你的项目能不能快速编译、能不能安全发布、能不能在 CI/CD 中高效运转。</p><p>一个配置混乱的 Maven 或 Gradle 项目，往往是团队工程化水平最直观的体现。</p><h2 id="模块速览" tabindex="-1">模块速览 <a class="header-anchor" href="#模块速览" aria-label="Permalink to “模块速览”">​</a></h2><table tabindex="0"><thead><tr><th>方向</th><th>篇数</th><th>核心目标</th></tr></thead><tbody><tr><td><a href="/devops/build-tool/history">构建工具基础</a></td><td>2 篇</td><td>发展历程、Maven vs Gradle 选型</td></tr><tr><td><a href="/devops/build-tool/maven-concept">Maven</a></td><td>11 篇</td><td>依赖管理、生命周期、插件机制、多模块项目</td></tr><tr><td><a href="/devops/build-tool/gradle-concept">Gradle</a></td><td>10 篇</td><td>DSL 语法、增量构建、多项目、守护进程</td></tr><tr><td><a href="/devops/build-tool/dependency-version">构建最佳实践</a></td><td>5 篇</td><td>版本规范、多环境、安全扫描、面试汇总</td></tr></tbody></table><h2 id="为什么需要专门的构建工具知识" tabindex="-1">为什么需要专门的构建工具知识？ <a class="header-anchor" href="#为什么需要专门的构建工具知识" aria-label="Permalink to “为什么需要专门的构建工具知识？”">​</a></h2><p>说个真实场景——你的项目突然构建失败，日志里全是 <code>Could not resolve dependencies</code>，或者依赖版本冲突导致运行时 <code>NoSuchMethodError</code>。这时你会发现：</p><ul><li>你需要理解 Maven 的<strong>依赖传递</strong>和<strong>依赖调解</strong>机制</li><li>你需要知道 Gradle 的 <strong>API vs Implementation</strong> 隔离是如何工作的</li><li>你需要掌握<strong>依赖分析</strong>和<strong>版本锁定</strong>的正确姿势</li></ul><p>这些不是「会用」就能解决的，需要深入理解其原理。</p><h2 id="学习路径建议" tabindex="-1">学习路径建议 <a class="header-anchor" href="#学习路径建议" aria-label="Permalink to “学习路径建议”">​</a></h2><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>第一阶段：理解核心概念（1-2 天）</span></span>
<span class="line"><span>→ Maven 坐标、仓库、依赖传递、作用域</span></span>
<span class="line"><span>→ Gradle Project、Task、构建脚本基础</span></span>
<span class="line"><span>→ 对比理解：Maven 的约定优于配置 vs Gradle 的灵活性</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第二阶段：掌握常用操作（2-3 天）</span></span>
<span class="line"><span>→ Maven 多模块项目搭建与依赖管理</span></span>
<span class="line"><span>→ Gradle 增量构建与任务缓存</span></span>
<span class="line"><span>→ 掌握依赖分析命令：mvn dependency:tree / gradle dependencies</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第三阶段：进阶与最佳实践（3-5 天）</span></span>
<span class="line"><span>→ Maven Profile 与 Gradle ProductFlavors 多环境构建</span></span>
<span class="line"><span>→ 构建性能优化：并行构建、本地缓存、增量编译</span></span>
<span class="line"><span>→ 依赖安全：漏洞扫描、版本锁定策略</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第四阶段：面试准备（1-2 天）</span></span>
<span class="line"><span>→ 依赖冲突的排查与解决思路</span></span>
<span class="line"><span>→ Maven 与 Gradle 的底层差异</span></span>
<span class="line"><span>→ 构建工具在 CI/CD 中的角色</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br></div></div><h2 id="面试的核心逻辑" tabindex="-1">面试的核心逻辑 <a class="header-anchor" href="#面试的核心逻辑" aria-label="Permalink to “面试的核心逻辑”">​</a></h2><p>构建工具的面试题看似简单，但区分度很高：</p><ol><li><strong>依赖管理深度</strong>：能不能说清楚依赖传递的副作用？依赖调解的「就近原则」怎么工作的？<code>dependencyManagement</code> 和普通 <code>dependencies</code> 的区别是什么？</li><li><strong>生命周期理解</strong>：Maven 的三套生命周期是相互独立还是有序执行？Clean 和 Default 之间的边界在哪里？</li><li><strong>性能意识</strong>：有没有排查过构建性能问题？增量构建和并行构建的原理是什么？</li><li><strong>选型判断</strong>：在什么场景下选 Maven，什么场景下选 Gradle？Spring Boot 选择 Gradle 的原因是什么？</li></ol><blockquote><p>&quot;会配置 Maven 和懂 Maven 是两回事。前者让你能跑起来，后者让你能在构建失败时快速定位问题，在构建缓慢时知道从哪里优化。&quot;</p></blockquote>`,16)])])}const u=a(p,[["render",r]]);export{h as __pageData,u as default};
